import{_ as a,o as i,c as t,ai as o}from"./chunks/framework.DG6aArJf.js";const p=JSON.parse('{"title":"Contributing Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"creator/contributing.md","filePath":"creator/contributing.md"}'),n={name:"creator/contributing.md"};function r(l,e,s,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o(`<p>y<a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a></p><p><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="contributing-guidelines" tabindex="-1">Contributing Guidelines <a class="header-anchor" href="#contributing-guidelines" aria-label="Permalink to “Contributing Guidelines”">​</a></h1><p>Thank you for your interest in contributing to DOM Helpers! Every contribution — whether it&#39;s a bug report, a documentation fix, or a new feature — helps make the library better for everyone.</p><hr><h2 id="ways-to-contribute" tabindex="-1">Ways to Contribute <a class="header-anchor" href="#ways-to-contribute" aria-label="Permalink to “Ways to Contribute”">​</a></h2><h3 id="report-a-bug" tabindex="-1">Report a Bug <a class="header-anchor" href="#report-a-bug" aria-label="Permalink to “Report a Bug”">​</a></h3><p>If you found something that isn&#39;t working as expected:</p><ol><li>Check the <a href="https://github.com/giovanni1707/DOMHelpers-Core/issues" target="_blank" rel="noreferrer">existing issues</a> to see if it&#39;s already reported</li><li>If not, open a new issue with: <ul><li>A clear title describing the problem</li><li>The module and method involved (e.g. <code>Elements.update()</code>)</li><li>A minimal code snippet that reproduces the bug</li><li>What you expected to happen vs. what actually happened</li><li>Your browser and environment</li></ul></li></ol><h3 id="suggest-a-feature" tabindex="-1">Suggest a Feature <a class="header-anchor" href="#suggest-a-feature" aria-label="Permalink to “Suggest a Feature”">​</a></h3><p>Have an idea that would make DOM Helpers more useful?</p><ol><li>Open an issue with the label <code>enhancement</code></li><li>Describe the use case — what problem does this solve?</li><li>Show what the API might look like with a code example</li></ol><h3 id="improve-the-documentation" tabindex="-1">Improve the Documentation <a class="header-anchor" href="#improve-the-documentation" aria-label="Permalink to “Improve the Documentation”">​</a></h3><p>Documentation contributions are especially welcome. If a page is unclear, missing an example, or contains a typo:</p><ol><li>Fork the repository</li><li>Edit the relevant <code>.md</code> file inside the <code>docs/</code> folder</li><li>Submit a pull request with a short description of what you changed and why</li></ol><h3 id="submit-a-pull-request" tabindex="-1">Submit a Pull Request <a class="header-anchor" href="#submit-a-pull-request" aria-label="Permalink to “Submit a Pull Request”">​</a></h3><p>For code changes:</p><ol><li>Fork the repository and create a branch from <code>main</code></li><li>Name your branch descriptively: <code>fix/collections-update-bug</code> or <code>feat/selector-waitfor</code></li><li>Make your changes in the <code>src/</code> folder</li><li>Keep each pull request focused on a single change — avoid bundling unrelated fixes</li><li>Write a clear PR description explaining what changed and why</li><li>Submit the pull request against the <code>main</code> branch</li></ol><hr><h2 id="code-style" tabindex="-1">Code Style <a class="header-anchor" href="#code-style" aria-label="Permalink to “Code Style”">​</a></h2><ul><li>Use plain JavaScript — no TypeScript, no build-step dependencies</li><li>Follow the IIFE module pattern used in existing files: <code>(function(global) { ... })(window)</code></li><li>Keep each module self-contained — avoid cross-module dependencies unless intentional</li><li>Add JSDoc comments for any new public methods following the existing style</li><li>Do not introduce external dependencies</li></ul><hr><h2 id="commit-messages" tabindex="-1">Commit Messages <a class="header-anchor" href="#commit-messages" aria-label="Permalink to “Commit Messages”">​</a></h2><p>Use short, descriptive commit messages in the imperative mood:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fix: resolve Collections.update null reference on empty selector</span></span>
<span class="line"><span>feat: add Router.enableScrollMemory to guards module</span></span>
<span class="line"><span>docs: clarify onCleanup usage in SPA Router page</span></span></code></pre></div><hr><h2 id="questions" tabindex="-1">Questions <a class="header-anchor" href="#questions" aria-label="Permalink to “Questions”">​</a></h2><p>If you&#39;re unsure about anything before opening a PR, open an issue first and describe what you&#39;re planning. It&#39;s easier to align early than to review a large change that goes in the wrong direction.</p><hr><p>Thank you for using DOM Helpers! Your feedback and support help make this library better for everyone.</p>`,30)])])}const g=a(n,[["render",r]]);export{p as __pageData,g as default};
